import{_ as e,c as o,o as r,ag as l}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"自注意力与交叉注意力：区别与实战理解","description":"","frontmatter":{"order":15},"headers":[],"relativePath":"ai/self-attention-and-cross-attention.md","filePath":"ai/self-attention-and-cross-attention.md","lastUpdated":1772197851000}'),a={name:"ai/self-attention-and-cross-attention.md"};function i(n,t,d,s,c,h){return r(),o("div",null,t[0]||(t[0]=[l('<h1 id="自注意力与交叉注意力-区别与实战理解" tabindex="-1">自注意力与交叉注意力：区别与实战理解 <a class="header-anchor" href="#自注意力与交叉注意力-区别与实战理解" aria-label="Permalink to &quot;自注意力与交叉注意力：区别与实战理解&quot;">​</a></h1><blockquote><p>📅 主题：Self-Attention vs Cross-Attention，在 Transformer 里各自做什么</p></blockquote><h2 id="一、先说结论" tabindex="-1">一、先说结论 <a class="header-anchor" href="#一、先说结论" aria-label="Permalink to &quot;一、先说结论&quot;">​</a></h2><ul><li><strong>自注意力（Self-Attention）</strong>：在同一序列内部建模关系，回答“这一段内容内部谁和谁相关”。</li><li><strong>交叉注意力（Cross-Attention）</strong>：在两个序列之间建模关系，回答“当前生成内容应该关注输入的哪一部分”。</li></ul><p>一句话：<br><strong>自注意力管“内部理解”，交叉注意力管“跨序列对齐”。</strong></p><hr><h2 id="二、自注意力-self-attention-是什么" tabindex="-1">二、自注意力（Self-Attention）是什么 <a class="header-anchor" href="#二、自注意力-self-attention-是什么" aria-label="Permalink to &quot;二、自注意力（Self-Attention）是什么&quot;">​</a></h2><p>在自注意力中，Q、K、V 来自同一个序列。<br> 例如句子 <code>我 喜欢 机器 学习</code>，每个 token 都会和这句话里的其他 token 计算相关性。</p><p>作用：</p><ol><li>建立全局依赖（不受固定窗口限制）</li><li>让每个 token 拿到“上下文增强表示”</li><li>支撑语义理解、指代消解、关系建模</li></ol><p>常见位置：</p><ul><li>Encoder 层：标准自注意力（可看全句）</li><li>Decoder 层：掩码自注意力（只能看已生成部分）</li></ul><hr><h2 id="三、交叉注意力-cross-attention-是什么" tabindex="-1">三、交叉注意力（Cross-Attention）是什么 <a class="header-anchor" href="#三、交叉注意力-cross-attention-是什么" aria-label="Permalink to &quot;三、交叉注意力（Cross-Attention）是什么&quot;">​</a></h2><p>在交叉注意力中：</p><ul><li>Q 来自 <strong>当前序列</strong>（通常是 Decoder 隐状态）</li><li>K、V 来自 <strong>另一序列</strong>（通常是 Encoder 输出）</li></ul><p>这意味着：Decoder 在生成每个 token 时，会去“查阅”输入序列表示。</p><p>作用：</p><ol><li>实现输入与输出的对齐（alignment）</li><li>避免生成时脱离输入内容</li><li>对翻译、摘要、问答这类 seq2seq 任务非常关键</li></ol><hr><h2 id="四、结构对比-最重要" tabindex="-1">四、结构对比（最重要） <a class="header-anchor" href="#四、结构对比-最重要" aria-label="Permalink to &quot;四、结构对比（最重要）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>自注意力</th><th>交叉注意力</th></tr></thead><tbody><tr><td>Q 来源</td><td>当前序列</td><td>当前序列（通常 Decoder）</td></tr><tr><td>K/V 来源</td><td>当前序列</td><td>另一序列（通常 Encoder 输出）</td></tr><tr><td>目标</td><td>建模序列内部关系</td><td>建模输入-输出关系</td></tr><tr><td>典型用途</td><td>语义理解、上下文融合</td><td>条件生成、信息对齐</td></tr><tr><td>主要出现位置</td><td>Encoder、Decoder</td><td>Decoder（Encoder-Decoder 架构）</td></tr></tbody></table><hr><h2 id="五、decoder-里为何两者都需要" tabindex="-1">五、Decoder 里为何两者都需要 <a class="header-anchor" href="#五、decoder-里为何两者都需要" aria-label="Permalink to &quot;五、Decoder 里为何两者都需要&quot;">​</a></h2><p>以标准 Encoder-Decoder Transformer 为例，Decoder 每层通常有两块注意力：</p><ol><li><strong>Masked Self-Attention</strong><ul><li>让模型只看已生成 token，保持自回归一致性</li></ul></li><li><strong>Cross-Attention</strong><ul><li>让当前生成步骤读取输入信息，防止“只会续写不会对齐”</li></ul></li></ol><p>如果只有第一块，模型更像“语言模型续写”；<br> 有了第二块，模型才具备“根据输入生成输出”的能力。</p><hr><h2 id="六、直观例子-翻译任务" tabindex="-1">六、直观例子：翻译任务 <a class="header-anchor" href="#六、直观例子-翻译任务" aria-label="Permalink to &quot;六、直观例子：翻译任务&quot;">​</a></h2><p>任务：把 <code>I love machine learning</code> 翻译成中文。</p><p>当 Decoder 生成“机器”这个词时：</p><ul><li><strong>自注意力</strong>：关注已生成的“我”“喜欢”等，保证中文句子自身连贯；</li><li><strong>交叉注意力</strong>：回看输入中 <code>machine</code>、<code>learning</code> 附近信息，决定该词和后续词如何对应。</li></ul><p>最终效果是：既满足中文表达流畅，又和原文语义对齐。</p><hr><h2 id="七、在大模型架构里的体现" tabindex="-1">七、在大模型架构里的体现 <a class="header-anchor" href="#七、在大模型架构里的体现" aria-label="Permalink to &quot;七、在大模型架构里的体现&quot;">​</a></h2><h2 id="_7-1-decoder-only-gpt-类" tabindex="-1">7.1 Decoder-only（GPT 类） <a class="header-anchor" href="#_7-1-decoder-only-gpt-类" aria-label="Permalink to &quot;7.1 Decoder-only（GPT 类）&quot;">​</a></h2><ul><li>主体是（因果）自注意力</li><li>通常没有显式 Cross-Attention 模块</li><li>若接入外部上下文（RAG 片段），一般通过拼接到上下文窗口，让自注意力统一处理</li></ul><h2 id="_7-2-encoder-decoder-t5-bart-类" tabindex="-1">7.2 Encoder-Decoder（T5/BART 类） <a class="header-anchor" href="#_7-2-encoder-decoder-t5-bart-类" aria-label="Permalink to &quot;7.2 Encoder-Decoder（T5/BART 类）&quot;">​</a></h2><ul><li>Encoder 用自注意力理解输入</li><li>Decoder 同时用掩码自注意力 + 交叉注意力生成输出</li><li>在翻译、摘要等 seq2seq 任务上更天然</li></ul><hr><h2 id="八、工程视角-常见问题与优化" tabindex="-1">八、工程视角：常见问题与优化 <a class="header-anchor" href="#八、工程视角-常见问题与优化" aria-label="Permalink to &quot;八、工程视角：常见问题与优化&quot;">​</a></h2><ol><li><p><strong>输出不对齐输入</strong></p><ul><li>可能是检索片段质量差、输入上下文噪声大，或对齐信号弱</li><li>优化：提高输入质量、减少噪声、明确“仅依据输入回答”的约束</li></ul></li><li><p><strong>长上下文成本高</strong></p><ul><li>注意力复杂度随长度增长快（尤其全局注意力）</li><li>优化：KV Cache、分块检索、滑窗策略、稀疏注意力等</li></ul></li><li><p><strong>关注错位</strong></p><ul><li>模型可能过度关注开头或结尾</li><li>优化：调整上下文排布，把关键证据放在问题附近，必要时加引用要求</li></ul></li></ol><hr><h2 id="九、与-rag-agent-的关系" tabindex="-1">九、与 RAG / Agent 的关系 <a class="header-anchor" href="#九、与-rag-agent-的关系" aria-label="Permalink to &quot;九、与 RAG / Agent 的关系&quot;">​</a></h2><ul><li><p><strong>RAG</strong>：检索到的文档片段本质是给模型提供外部上下文。<br> 在 Decoder-only 模型里，这些片段通过自注意力被利用；在 Encoder-Decoder 体系里，也可通过类似“输入编码 → 输出对齐”的机制发挥作用。</p></li><li><p><strong>Agent</strong>：在多步任务中，模型每一步都在“基于当前上下文做选择”。<br> 自注意力决定其如何整合历史和当前状态；若有显式输入-输出对齐链路，交叉注意力会直接影响行动决策质量。</p></li></ul><hr><h2 id="十、小结" tabindex="-1">十、小结 <a class="header-anchor" href="#十、小结" aria-label="Permalink to &quot;十、小结&quot;">​</a></h2><ol><li>自注意力解决“同一序列内部如何彼此关注”。</li><li>交叉注意力解决“当前生成如何关注外部输入”。</li><li>在 Encoder-Decoder 中，二者是互补关系：一个保连贯，一个保对齐。</li><li>理解这两类注意力，有助于解释模型在翻译、摘要、RAG、Agent 场景中的行为差异。</li><li>做应用优化时，除了调 Prompt，更要调输入质量与上下文结构，让“该被关注的信息”更容易被注意到。</li></ol><p>掌握这组概念后，Transformer 的核心注意力机制链路就完整了。</p>',49)]))}const g=e(a,[["render",i]]);export{p as __pageData,g as default};
